SELECT debate_id, aff_team_id, neg_team_id, judge_id, result, debate_location
FROM debates
WHERE debate_id = 1;

SELECT name
FROM debaters
WHERE debater_id = 0;

SELECT COUNT(*) AS number_of_debaters
FROM debaters
WHERE school_id = (SELECT school_id FROM schools WHERE name = 'Cypress Bay High School');
